export interface CSVOptions {
  delimiter?: string;
  quoteChar?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  headers: string[];
  rows: Array<Record<string, unknown>>;
  errors: CSVError[];
  filter(predicate: (row: Record<string, unknown>) => boolean): Array<Record<string, unknown>>;
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<unknown, Array<Record<string, unknown>>>;
}

const defaultOptions: Required<CSVOptions> = {
  delimiter: ",",
  quoteChar: '"',
  lineSeparator: "\n",
};

function isLineSeparatorAt(input: string, index: number, lineSeparator?: string): string | null {
  if (lineSeparator) {
    if (input.startsWith(lineSeparator, index)) {
      return lineSeparator;
    }
    return null;
  }

  if (input.startsWith("\r\n", index)) {
    return "\r\n";
  }
  if (input.startsWith("\n", index)) {
    return "\n";
  }
  if (input.startsWith("\r", index)) {
    return "\r";
  }
  return null;
}

function coerceValue(value: string): unknown {
  const trimmed = value.trim();
  if (trimmed === "") {
    return null;
  }
  const lower = trimmed.toLowerCase();
  if (lower === "null") {
    return null;
  }
  if (lower === "true") {
    return true;
  }
  if (lower === "false") {
    return false;
  }
  if (/^-?(?:\d+\.?\d*|\d*\.\d+)$/.test(trimmed)) {
    const num = Number(trimmed);
    if (!Number.isNaN(num)) {
      return num;
    }
  }
  return value;
}

function parseRows(input: string, options: Required<CSVOptions>): { rows: string[][]; errors: CSVError[] } {
  const rows: string[][] = [];
  const errors: CSVError[] = [];

  if (input.length === 0) {
    return { rows, errors };
  }

  let row: string[] = [];
  let field = "";
  let inQuotes = false;
  let lineNumber = 1;

  for (let i = 0; i < input.length; i += 1) {
    const char = input[i];

    if (inQuotes) {
      if (char === options.quoteChar) {
        const nextChar = input[i + 1];
        if (nextChar === options.quoteChar) {
          field += options.quoteChar;
          i += 1;
        } else {
          inQuotes = false;
        }
      } else {
        field += char;
      }
      continue;
    }

    const lineSeparator = isLineSeparatorAt(
      input,
      i,
      options.lineSeparator === "" ? undefined : options.lineSeparator
    );

    if (lineSeparator) {
      row.push(field);
      rows.push(row);
      row = [];
      field = "";
      lineNumber += 1;
      i += lineSeparator.length - 1;
      continue;
    }

    if (char === options.delimiter) {
      row.push(field);
      field = "";
      continue;
    }

    if (char === options.quoteChar) {
      inQuotes = true;
      continue;
    }

    field += char;
  }

  if (inQuotes) {
    errors.push({ row: lineNumber, message: "Unclosed quoted field" });
  }

  row.push(field);
  if (row.length > 1 || row[0] !== "" || input.endsWith(options.delimiter)) {
    rows.push(row);
  }

  return { rows, errors };
}

export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const mergedOptions: Required<CSVOptions> = {
    delimiter: options.delimiter ?? defaultOptions.delimiter,
    quoteChar: options.quoteChar ?? defaultOptions.quoteChar,
    lineSeparator: options.lineSeparator ?? defaultOptions.lineSeparator,
  };

  const { rows: rawRows, errors } = parseRows(input, mergedOptions);

  const headers = rawRows.length > 0 ? rawRows[0].map((header) => header.trim()) : [];
  const dataRows = rawRows.slice(1);

  const rows: Array<Record<string, unknown>> = dataRows.map((rawRow, index) => {
    if (rawRow.length !== headers.length) {
      errors.push({
        row: index + 2,
        message: `Expected ${headers.length} columns but got ${rawRow.length}`,
      });
    }

    const record: Record<string, unknown> = {};
    headers.forEach((header, headerIndex) => {
      const value = rawRow[headerIndex] ?? "";
      record[header] = coerceValue(value);
    });
    return record;
  });

  const result: CSVResult = {
    headers,
    rows,
    errors,
    filter(predicate) {
      return this.rows.filter(predicate);
    },
    sum(column) {
      return this.rows.reduce((total, row) => {
        const value = row[column];
        if (typeof value === "number" && !Number.isNaN(value)) {
          return total + value;
        }
        return total;
      }, 0);
    },
    average(column) {
      let total = 0;
      let count = 0;
      this.rows.forEach((row) => {
        const value = row[column];
        if (typeof value === "number" && !Number.isNaN(value)) {
          total += value;
          count += 1;
        }
      });
      return count === 0 ? 0 : total / count;
    },
    count() {
      return this.rows.length;
    },
    groupBy(column) {
      const map = new Map<unknown, Array<Record<string, unknown>>>();
      this.rows.forEach((row) => {
        const key = row[column];
        const group = map.get(key);
        if (group) {
          group.push(row);
        } else {
          map.set(key, [row]);
        }
      });
      return map;
    },
  };

  return result;
}

import { parseCSV } from "./csv-parser";

function assert(condition: boolean, message: string) {
  if (!condition) {
    throw new Error(message);
  }
}

function assertEqual(actual: unknown, expected: unknown, message: string) {
  if (actual !== expected) {
    throw new Error(`${message} (expected ${expected}, got ${actual})`);
  }
}

function assertDeepEqual(actual: unknown, expected: unknown, message: string) {
  const actualJson = JSON.stringify(actual);
  const expectedJson = JSON.stringify(expected);
  if (actualJson !== expectedJson) {
    throw new Error(`${message} (expected ${expectedJson}, got ${actualJson})`);
  }
}

