  const input = "name,age\nAlice,30\nBob,25";
  const result = parseCSV(input);
  assertDeepEqual(result.headers, ["name", "age"], "Headers parsed");
  assertEqual(result.rows.length, 2, "Two rows parsed");
  assertEqual(result.rows[0].name, "Alice", "First row name");
  assertEqual(result.rows[0].age, 30, "First row age coerced");
})();

(function testQuotedFieldsWithCommas() {
  const input = "name,notes\nAlice,\"hello, world\"";
  const result = parseCSV(input);
  assertEqual(result.rows[0].notes, "hello, world", "Quoted field with comma parsed");
})();

(function testEscapedQuotes() {
  const input = "name,quote\nAlice,\"He said \"\"hi\"\"\"";
  const result = parseCSV(input);
  assertEqual(result.rows[0].quote, "He said \"hi\"", "Escaped quotes parsed");
})();

(function testCustomDelimiters() {
  const input = "a;b|1;2|3;4";
  const result = parseCSV(input, { delimiter: ";", lineSeparator: "|" });
  assertDeepEqual(result.headers, ["a", "b"], "Custom delimiter headers");
  assertEqual(result.rows.length, 2, "Custom line separator rows");
})();

(function testTypeCoercion() {
  const input = "i,f,t,f2,n,empty,text\n42,3.14,true,FALSE,NULL,,hello";
  const result = parseCSV(input);
  const row = result.rows[0];
  assertEqual(row.i, 42, "Integer coercion");
  assertEqual(row.f, 3.14, "Float coercion");
  assertEqual(row.t, true, "Boolean true coercion");
  assertEqual(row.f2, false, "Boolean false coercion");
  assertEqual(row.n, null, "Null coercion");
  assertEqual(row.empty, null, "Empty string coercion");
  assertEqual(row.text, "hello", "String stays string");
})();

(function testMalformedRowErrorCollection() {
  const input = "a,b\n1,2,3";
  const result = parseCSV(input);
  assertEqual(result.errors.length, 1, "Malformed row error collected");
  assertEqual(result.errors[0].row, 2, "Malformed row number recorded");
})();

(function testFilterFunctionality() {
  const input = "name,age\nAlice,30\nBob,20\nCharlie,40";
  const result = parseCSV(input);
  const filtered = result.filter((row) => (row.age as number) > 25);
  assertEqual(filtered.length, 2, "Filter returns matching rows");
})();

(function testAggregationMethods() {
  const input = "name,score,team\nA,10,red\nB,20,blue\nC,30,red";
  const result = parseCSV(input);
  assertEqual(result.sum("score"), 60, "Sum aggregates numbers");
  assertEqual(result.average("score"), 20, "Average aggregates numbers");
  assertEqual(result.count(), 3, "Count returns total rows");
  const grouped = result.groupBy("team");
  assertEqual(grouped.get("red")?.length, 2, "GroupBy groups rows");
})();

(function testEdgeCases() {
  const empty = parseCSV("");
  assertEqual(empty.headers.length, 0, "Empty input headers");
  assertEqual(empty.rows.length, 0, "Empty input rows");

  const singleColumn = parseCSV("value\n1\n2");
  assertEqual(singleColumn.headers.length, 1, "Single column header");
  assertEqual(singleColumn.rows.length, 2, "Single column rows");

  const singleRow = parseCSV("a,b\n1,2");
  assertEqual(singleRow.rows.length, 1, "Single row parsed");

  const largeField = "a".repeat(10000);
  const largeInput = `field\n\"${largeField}\"`;
  const largeResult = parseCSV(largeInput);
  assertEqual(largeResult.rows[0].field, largeField, "Large field parsed");
})();

console.log("All tests passed.");

